    parentID: CatalogObjectID? = nil, targetID: CatalogObjectID? = nil, name: String? = nil,
    mode: UInt32? = nil, contentRevision: UInt64? = nil, linkTarget: String? = nil
  ) throws {
    self.protocolVersion = protocolVersion
